import requests
import json

# Define the base URL for the management plugin REST API
base_url = 'http://localhost:15672/api'
username = 'guest'  # username of your RabbitMQ server, can be set by user
password = 'guest'  # password of your RabbitMU server, can be set by user

# Function to create virtual hosts
def create_vhost(name):
    url = f"{base_url}/vhosts/{name}"
    payload = {}
    headers = {
        'content-type': "application/json",
        'cache-control': "no-cache"
    }
    response = requests.put(url, data=json.dumps(payload), headers=headers, auth=(username, password))
    if response.status_code == 201:
        print(f'Successfully created vhost {name}')
    elif response.status_code == 405:  # 405 Method Not Allowed implies that the vhost already exists
        print(f'Vhost {name} already exists')
    else:
        raise Exception(f"Error creating vhost {name}. Status code: {response.status_code}, content: {response.text}")

# Function to create users
def create_user(name, password):
    url = f"{base_url}/users/{name}"
    payload = {"password": password, "tags": ""}
    headers = {
        'content-type': "application/json",
        'cache-control': "no-cache"
    }
    response = requests.put(url, data=json.dumps(payload), headers=headers, auth=(username, password))
    if response.status_code == 201:
        print(f'Successfully created user {name}')
    elif response.status_code == 405:  # 405 Method Not Allowed implies that the user already exists
        print(f'User {name} already exists')
    else:
        raise Exception(f"Error creating user {name}. Status code: {response.status_code}, content: {response.text}")

# Function to grant permissions to a user for all queues in all vhosts
def set_permissions(user, vhost):
    url = f"{base_url}/permissions/{vhost}/{user}"
    payload = {"configure": ".*", "write": ".*", "read": ".*"}  # Full permissions for configure, write and read operations
    headers = {
        'content-type': "application/json",
        'cache-control': "no-cache"
    }
    response = requests.put(url, data=json.dumps(payload), headers=headers, auth=(username, password))
    if response.status_code == 200:
        print(f'Successfully granted permissions to user {user} on vhost {vhost}')
    else:
        raise Exception(f"Error granting permissions for user {user} on vhost {vhost}. Status code: {response.status_code}, content: {response.text}")